export const mockScheduledLessons: ScheduledLessonDto[] = scheduleLessonsSeed.map((l) => ({
  ...l,
  description: l.description ?? l.notes ?? `Materials, homework, and updates for “${l.title}”.`,
}));

export const lessonEntities = mockScheduledLessons;

export type MockLesson = {
  id: string;
  title: string;
  level: 'A1' | 'A2' | 'B1' | 'B2' | 'C1' | 'C2';
  duration: number;
  xp: number;
  difficulty: 'easy' | 'medium' | 'hard';
  description: string;
  completed: boolean;
  locked: boolean;
  visibilityByRole: UserRole[];
};

export const mockLessons: MockLesson[] = mockScheduledLessons.map((lesson) => ({
  id: lesson.lessonId ?? lesson.id,
  title: lesson.title,
  level: 'B2',
  duration: lesson.duration,
  xp: 30,
  difficulty: 'medium',
  description: lesson.description ?? lesson.notes ?? `${lesson.title} lesson`,
  completed: lesson.status === 'completed',
  locked: false,
  visibilityByRole: ['student', 'teacher', 'admin', 'super-admin'],
}));

export const getLessonsForAccount = (accountId: string): MockLesson[] =>
  accountId === mockAccounts[0].id ? mockLessons : [];

export function getStudentScheduledLessons(
  studentId: string,
): ScheduledLessonDto[] {
  return mockScheduledLessons.filter(lesson => lesson.studentId === studentId);
}
