import type {
  ProfileVocabularyEntry,
  ScheduledLessonDto,
  VocabularyWordDto,
  VocabularyWordStatus,
} from '@soenglish/shared-types';
import { activeAccount, activeUser, type MockUser, type UserRole } from '../session';
import { buildProfileAchievements, emptyProfileStats, type ProfileAchievement, type ProfileStats } from './achievements';
import {
  mockPracticeActivitiesByEntity,
  mockProfileGoalsByEntity,
  mockProfileMeta,
  mockProfiles,
  mockProfileStatsByEntity,
  mockUsers,
} from './entities';
import { getVocabularyWordById } from './vocabulary';

/** Stored row: profile entry + tenancy (mock persistence). */
export type ProfileVocabularyRow = ProfileVocabularyEntry & {
  accountId: string;
  userId: string;
};

const PROFILE_VOCAB_ACCOUNT_ID = 'account-main';

/** Seed vocabulary progress grouped per student user id (flattened into profileVocabularyRows). */
function buildSeedProfileVocabularyRows(): ProfileVocabularyRow[] {
  const forUser = (
    userId: string,
    entries: Array<{
      id: string;
      vocabularyId: string;
      lessonId?: string;
      status: VocabularyWordStatus;
    }>,
  ): ProfileVocabularyRow[] =>
    entries.map((e) => ({
      id: e.id,
      accountId: PROFILE_VOCAB_ACCOUNT_ID,
      userId,
      vocabularyId: e.vocabularyId,
      lessonId: e.lessonId,
      status: e.status,
    }));

  return [
    ...forUser('student-1', [
      { id: 'pv-1', vocabularyId: '1', status: 'new' },
      { id: 'pv-2', vocabularyId: '2', lessonId: 'lesson-cal-1', status: 'learning' },
      { id: 'pv-3', vocabularyId: '3', status: 'known' },
      { id: 'pv-4', vocabularyId: '4', status: 'learning' },
      { id: 'pv-5', vocabularyId: '5', lessonId: 'lesson-cal-4', status: 'new' },
    ]),
    ...forUser('student-2', [
      { id: 'pv-6', vocabularyId: '1', status: 'learning' },
      { id: 'pv-7', vocabularyId: '3', lessonId: 'lesson-cal-14', status: 'new' },
    ]),
  ];
}

export let profileVocabularyRows: ProfileVocabularyRow[] = buildSeedProfileVocabularyRows();

export function getProfileVocabularyForUser(accountId: string, userId: string): ProfileVocabularyRow[] {
  return profileVocabularyRows.filter((r) => r.accountId === accountId && r.userId === userId);
}

function profileVocabularyRowKey(
  accountId: string,
  userId: string,
  vocabularyId: string,
  lessonId: string | undefined,
) {
  return `${accountId}|${userId}|${vocabularyId}|${lessonId ?? ''}`;
}

/** Join profile rows with global vocabulary entries (drops orphan vocabulary ids). */
export type VocabularyProgressItem = {
  row: ProfileVocabularyRow;
  word: VocabularyWordDto;
};

export function joinProfileVocabulary(accountId: string, userId: string): VocabularyProgressItem[] {
  const out: VocabularyProgressItem[] = [];
  for (const row of getProfileVocabularyForUser(accountId, userId)) {
    const word = getVocabularyWordById(row.vocabularyId);
    if (word) out.push({ row, word });
  }
  return out;
}

export function updateProfileVocabularyStatus(entryId: string, status: VocabularyWordStatus): void {
  profileVocabularyRows = profileVocabularyRows.map((r) =>
    r.id === entryId ? { ...r, status } : r,
  );
}

export function addProfileVocabularyEntry(params: {
  accountId: string;
  userId: string;
  vocabularyId: string;
  lessonId?: string;
  status?: VocabularyWordStatus;
}): string {
  const key = profileVocabularyRowKey(
    params.accountId,
    params.userId,
    params.vocabularyId,
    params.lessonId,
  );
  const existing = profileVocabularyRows.find(
    (r) =>
      profileVocabularyRowKey(r.accountId, r.userId, r.vocabularyId, r.lessonId) === key,
  );
  if (existing) return existing.id;

  const id = `pv-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
  profileVocabularyRows = [
    ...profileVocabularyRows,
    {
      id,
      accountId: params.accountId,
      userId: params.userId,
      vocabularyId: params.vocabularyId,
      lessonId: params.lessonId,
      status: params.status ?? 'new',
    },
  ];
  return id;
}

/** Link lesson vocabulary to student profile (idempotent per user + word + lesson). */
export function ensureLessonVocabularyForStudent(params: {
  accountId: string;
  userId: string;
  lessonId: string;
  vocabularyId: string;
}): string {
  return addProfileVocabularyEntry({
    accountId: params.accountId,
    userId: params.userId,
    vocabularyId: params.vocabularyId,
    lessonId: params.lessonId,
    status: 'new',
  });
}

/** After lesson save: sync linked ids to the student profile (idempotent). */
export function syncLessonVocabularyToProfile(lesson: ScheduledLessonDto): void {
  const ids = lesson.linkedVocabularyIds;
  if (!ids?.length) return;
  const user = mockUsers.find((u) => u.id === lesson.studentId);
  const accountId = user?.accountId ?? PROFILE_VOCAB_ACCOUNT_ID;
  for (const vocabularyId of ids) {
    ensureLessonVocabularyForStudent({
      accountId,
      userId: lesson.studentId,
      lessonId: lesson.id,
      vocabularyId,
    });
  }
}

export function countKnownWordsForUser(accountId: string, userId: string): number {
  return getProfileVocabularyForUser(accountId, userId).filter((r) => r.status === 'known').length;
}

/** Dashboard “Review words” strip — shape compatible with previous mockReviewWords. */
export type ReviewWordSnapshot = {
  word: string;
  pos: string;
  def: string;
  status: VocabularyWordStatus;
};

export function getReviewWordsForUser(userId: string, accountId: string): ReviewWordSnapshot[] {
  return joinProfileVocabulary(accountId, userId).map(({ row, word }) => ({
    word: word.word,
    pos: word.pos,
    def: word.definition,
    status: row.status,
  }));
}

export const mockReviewWords: ReviewWordSnapshot[] = getReviewWordsForUser(activeUser.id, activeAccount.id);

export type MockProfileForm = {
  name: string;
  email: string;
  telegram: string;
  phone: string;
  timezone: string;
  nativeLanguage: string;
  targetLevel: string;
  weeklyGoal: string;
  bio: string;
};

export type ProfileViewModel = {
  id: string;
  accountId: string;
  userId: string;
  fullName: string;
  level: string;
  email: string;
  phone: string;
  timezone: string;
  notes: string;
  calendarColor?: string;
  status: 'active' | 'paused';
  scheduleType: 'fixed' | 'flexible';
  teacherId: string;
  teacherName: string;
  wordsLearned: number;
  lessonsCompleted: number;
  streakDays: number;
};

export type MockStudent = ProfileViewModel;

const toProfileViewModel = (userId: string): ProfileViewModel | null => {
  const user = mockUsers.find((entry) => entry.id === userId);
  const profile = mockProfiles.find((entry) => entry.userId === userId && entry.accountId === activeAccount.id);
  const profileMeta = mockProfileMeta.find((entry) => entry.userId === userId && entry.accountId === activeAccount.id);
  if (!user || user.role !== 'student' || !profile || !profileMeta) return null;
  const teacher = mockUsers.find((entry) => entry.id === profileMeta.teacherId);
  const stats = mockProfileStatsByEntity.find((entry) => entry.accountId === activeAccount.id && entry.userId === userId);
  return {
    id: user.id,
    accountId: user.accountId,
    userId: user.id,
    fullName: user.fullName,
    level: user.targetLevel,
    email: user.email,
    phone: profile.phone,
    timezone: profile.timezone,
    notes: profileMeta.notes,
    calendarColor: profileMeta.calendarColor,
    status: profileMeta.status,
    scheduleType: profileMeta.scheduleType,
    teacherId: profileMeta.teacherId,
    teacherName: teacher?.fullName ?? 'Unknown teacher',
    wordsLearned: countKnownWordsForUser(profile.accountId, user.id),
    lessonsCompleted: stats?.stats.lessonsCompleted ?? 0,
    streakDays: stats?.stats.streakDays ?? user.streakDays ?? 0,
  };
};

export const getProfileByUserId = (userId: string): ProfileViewModel | undefined =>
  toProfileViewModel(userId) ?? undefined;

export const getVisibleProfiles = (role: UserRole, userId: string): ProfileViewModel[] => {
  if (role === 'teacher') {
    return mockProfileMeta
      .filter((entry) => entry.accountId === activeAccount.id && entry.teacherId === userId)
      .map((entry) => toProfileViewModel(entry.userId))
      .filter((entry): entry is ProfileViewModel => Boolean(entry));
  }
  if (role === 'admin' || role === 'super-admin') {
    return mockProfileMeta
      .filter((entry) => entry.accountId === activeAccount.id)
      .map((entry) => toProfileViewModel(entry.userId))
      .filter((entry): entry is ProfileViewModel => Boolean(entry));
  }
  if (role === 'student') {
    const own = toProfileViewModel(userId);
    return own ? [own] : [];
  }
  return [];
};

export const canManageProfile = (currentUser: MockUser, profile: ProfileViewModel): boolean => {
  if (currentUser.role === 'teacher') return profile.teacherId === currentUser.id;
  return currentUser.role === 'admin' || currentUser.role === 'super-admin';
};

export const getProfileFormByUserId = (userId: string): MockProfileForm => {
  const user = mockUsers.find((entry) => entry.id === userId);
  const profile = mockProfiles.find((entry) => entry.userId === userId && entry.accountId === activeAccount.id);
  if (!user) {
    throw new Error(`Profile data is missing for user "${userId}" in account "${activeAccount.id}"`);
  }
  if (!profile) {
    return {
      name: user.fullName,
      email: user.email,
      telegram: '',
      phone: '',
      timezone: 'Europe/Kyiv',
      nativeLanguage: 'Ukrainian',
      targetLevel: user.targetLevel,
      weeklyGoal: '3',
      bio: '',
    };
  }
  return {
    name: user.fullName,
    email: user.email,
    telegram: profile.telegram,
    phone: profile.phone,
    timezone: profile.timezone,
    nativeLanguage: profile.nativeLanguage,
    targetLevel: user.targetLevel,
    weeklyGoal: profile.weeklyGoal,
    bio: profile.bio,
  };
};

export const mockProfileForm: MockProfileForm = getProfileFormByUserId(activeUser.id);

export const mockProfileStatsByAccount: Array<{ accountId: string; userId: string; stats: ProfileStats }> =
  mockProfileStatsByEntity.map((entry) => ({
    accountId: entry.accountId,
    userId: entry.userId,
    stats: entry.stats,
  }));

/** Uses stats from mockProfileStatsByAccount / mockProfileStatsByEntity for the given user. */
export function getProfileAchievementsForUserId(
  userId: string,
  accountId: string = activeAccount.id,
): ProfileAchievement[] {
  const entry = mockProfileStatsByAccount.find((row) => row.accountId === accountId && row.userId === userId);
  return buildProfileAchievements(entry?.stats ?? emptyProfileStats);
}

const activeStatsEntry = mockProfileStatsByAccount.find(
  (entry) => entry.accountId === activeAccount.id && entry.userId === activeUser.id,
);

export const mockProfileStats = activeStatsEntry?.stats ?? {
  ...emptyProfileStats,
  streakDays: activeUser.streakDays ?? 0,
};

export const mockProfileGoals = mockProfileGoalsByEntity
  .filter((goal) => goal.accountId === activeAccount.id && goal.userId === activeUser.id)
  .map((goal) => ({ text: goal.text, done: goal.done })) as ReadonlyArray<{ text: string; done: boolean }>;

export const mockPracticeActivities = mockPracticeActivitiesByEntity
  .filter((activity) => activity.accountId === activeAccount.id)
  .map((activity) => ({
    href: activity.href,
    title: activity.title,
    description: activity.description,
    icon: activity.icon,
    tag: activity.tag,
    tagClass: activity.tagClass,
    disabled: activity.disabled,
  })) as ReadonlyArray<{
  href: string;
  title: string;
  description: string;
  icon: string;
  tag: string;
  tagClass: 'tagGreen' | 'tagBlue' | 'tagAmber' | 'tagMuted';
  disabled?: boolean;
}>;
