/**
 * Achievements unlock from ProfileStats only (rules in this file). Each user's counters are
 * stored by userId in mockProfileStatsByEntity (`domains/entities.ts`). The UI resolves them
 * through mockProfileStatsByAccount (`domains/profile.ts`) and calls buildProfileAchievements(stats).
 */
export type ProfileStats = {
  wordsLearned: number;
  lessonsCompleted: number;
  streakDays: number;
  quizzesCompleted: number;
  perfectQuizCount: number;
  speakingSessions: number;
};

export const emptyProfileStats: ProfileStats = {
  wordsLearned: 0,
  lessonsCompleted: 0,
  streakDays: 0,
  quizzesCompleted: 0,
  perfectQuizCount: 0,
  speakingSessions: 0,
};

export type AchievementIconKey =
  | 'sparkles'
  | 'graduation-cap'
  | 'calendar-check'
  | 'flame'
  | 'book-open'
  | 'brain'
  | 'messages-square'
  | 'mic'
  | 'target'
  | 'badge-check'
  | 'star'
  | 'rocket'
  | 'trophy'
  | 'crown'
  | 'mountain'
  | 'gem';

export type ProfileAchievement = {
  icon: AchievementIconKey;
  label: string;
  description: string;
  unlocked: boolean;
};

type AchievementRule = {
  icon: AchievementIconKey;
  label: string;
  description: string;
  isUnlocked: (stats: ProfileStats) => boolean;
};

