export function buildProfileAchievements(
  stats: ProfileStats,
): ProfileAchievement[] {
  return profileAchievementRules.map((rule) => ({
    icon: rule.icon,
    label: rule.label,
    description: rule.description,
    unlocked: rule.isUnlocked(stats),
  }));
}
